/**
 * Lemon Squeezy API Types
 *
 * Type definitions for Lemon Squeezy License API responses
 */

export interface LemonSqueezyLicenseKey {
  id: number;
  status: 'inactive' | 'active' | 'expired' | 'disabled';
  key: string;
  activation_limit: number;
  activation_usage: number;
  created_at: string;
  expires_at: string | null;
}

export interface LemonSqueezyInstance {
  id: string;
  name: string;
  created_at: string;
}

export interface LemonSqueezyMeta {
  store_id: number | string;
  order_id: number;
  order_item_id: number;
  product_id: number;
  product_name: string;
  variant_id: number;
  variant_name: string;
  customer_id: number;
  customer_name: string;
  customer_email: string;
}

export interface LemonSqueezyLicenseResponse {
  valid: boolean;
  error: string | null;
  license_key: LemonSqueezyLicenseKey;
  instance: LemonSqueezyInstance;
  meta: LemonSqueezyMeta;
}

export interface LemonSqueezyErrorResponse {
  error: string;
}

export type LemonSqueezyApiResponse = LemonSqueezyLicenseResponse | LemonSqueezyErrorResponse;
